SET @company_id = 3;
SET @sa = (SELECT user_id FROM users WHERE login_id = 'cblim' LIMIT 1);

-- Step 0: 기존 마이그 데이터 전체 삭제
DELETE FROM customer_mileage WHERE company_id = @company_id;
DELETE FROM manual_gps_points WHERE ride_id IN (SELECT ride_id FROM rides WHERE company_id = @company_id);
DELETE FROM settlement_rides WHERE ride_id IN (SELECT ride_id FROM rides WHERE company_id = @company_id);
DELETE FROM rides WHERE company_id = @company_id;
UPDATE customers SET mileage_balance = 0 WHERE company_id = @company_id;

-- Step 1: 고객시트 274명 전부 NOT EXISTS INSERT
-- (이미 DB에 있는 고객은 자동 스킵, 없는 고객만 신규 등록)

SELECT 'Part 1 완료' AS status, (SELECT COUNT(*) FROM customers WHERE company_id=@company_id) AS customer_total;